head.script:
scwin.memJson = $c.data.getMemInfo();
console.log(scwin.memJson);
scwin.vEqHomeClsCd = scwin.memJson.eqHomeClsCd; //정비소속구분코드
scwin.vFixWrkPlCd = scwin.memJson.fixWrkPlCd; //정비작업장코드
scwin.currDate = WebSquare.date.getFormattedDate (new Date(), "yyyyMM");

scwin.onpageload = function() {
    const codeOptions = [ 
        { grpCd : "ZZ205", compID : "lc_homeClsCd, lc_homeClsCdSlip", opt :{"range" : "2,TR"} },
    ];
    $c.data.setCommonCode(codeOptions);

    ica_inYm.setValue(scwin.currDate);
    ica_inYmSlip.setValue(scwin.currDate);
};

// 공통코드가 셋팅이 되고 scwin.ondataload 이벤트가 호출
scwin.ondataload = function() { 
    lc_homeClsCd.setSelectedIndex(0);
    lc_homeClsCdSlip.setSelectedIndex(0);
    lc_homeClsCd.setValue(scwin.vEqHomeClsCd);
    lc_homeClsCdSlip.setValue(scwin.vEqHomeClsCd);
	// 대표정비작업장콤보 조회
    scwin.f_RetrieveSecondSlip(lc_homeClsCdSlip.getValue());
    ica_inYm.focus();
};

// UDC 셋팅이 이후..
scwin.onUdcCompleted = function() {
};

//-------------------------------------------------------------------------
// 조회 조건 지우기
//-------------------------------------------------------------------------

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
	// 필수입력항목 체크	  
    let ret = await $c.gus.cfValidate([ica_inYm]);
    if (!ret) {
        return false;
    }
    dma_search.set("wrkPlCd", lc_WrkPlCd.getValue());    
    $c.sbm.execute(sbm_search);
};

//-------------------------------------------------------------------------
// 전표생성여부 검사
//-------------------------------------------------------------------------
scwin.f_checkflag = async function(funCMD) {
	let check_flag	= "false";	//전표생성여부
	let slipNo		= "";		//전표번호

    for(let i=0; i< ds_eq420.getRowCount() ; i++) {
        let rowJson = ds_eq420.getRowJSON(i);
		check_flag = "true";
		slipNo = rowJson.slipNo;
		if( funCMD == "slipCreate" && slipNo.length > 0 ) {
            await $c.win.alert($c.data.getMessage(MSG_CM_ERR_055, " 생성된 전표가 있습니다. \n전표번호"));
			return false;
		}
		if ( funCMD == "slipDel" && slipNo.length < 1  ) {
            await $c.win.alert($c.data.getMessage(MSG_CM_ERR_055, " 생성된 전표가 없습니다. \n전표번호"));
			return false;
		}
	}

	if( check_flag == "true") { 
		return true;
	}else {
        await $c.win.alert($c.data.getMessage(MSG_CM_ERR_056, "항목"));
		return false;
	}
};

//-------------------------------------------------------------------------
// 전표생성
//-------------------------------------------------------------------------
scwin.f_slipCreate = async function() {

	// 필수입력항목 체크 
  	if ( ! await $c.gus.cfValidate([tbl_slipCond]) ) return;
  	if ( lc_WrkPlCdSlip.getValue() == "" ) {
  		await $c.win.alert("작업장을 선택하세요.");
  		lc_WrkPlCdSlip.focus();
  		return;
  	}

  	//전표생성여부 검사
	// if(!f_checkflag('slipCreate')) return;
	let rtn = "";
	let inYm = "";
	let wrkPlCd = "";
	inYm 	= ica_inYmSlip.getValue();
	wrkPlCd = lc_WrkPlCdSlip.getValue();
  	rtn = await udc_jobClose.cfJobCloseYN("CUR", inYm, "00", "EQ06", wrkPlCd, "", "N");

    let lc_WrkPlCdSlip_text = lc_WrkPlCdSlip.getItemArray()[lc_WrkPlCdSlip.getSelectedIndex()].orgLabel;

 	if ( rtn == "2" ) {
		await $c.win.alert( lc_WrkPlCdSlip_text + "에 대한 부품매입전표가 이미 생성되었습니다.");
		return;
	}

	if( await $c.win.confirm($c.data.getMessage(MSG_CM_CRM_009,"전표"))==true ){	//"@을(를) 생성하시겠습니까?"
		dma_slip_cond.set("inYm", ica_inYmSlip.getValue());
		dma_slip_cond.set("wrkPlCd", lc_WrkPlCdSlip.getValue());
		dma_slip_cond.set("vatAcctDeptCd", ed_acctDeptCd.getValue());
		// ds_slip_cond.UseChangeInfo="false";

		let inAmt = 0;
		let vatAmt = 0;
		for( let i=0; i<ds_eq420.getRowCount() ; i++) {
			ds_eq420.setCellData(i, "totAmt", ds_eq420.getCellData(i, "inAmt")  + ds_eq420.getCellData(i, "vatAmt") );
		}		
		// ds_eq420.UseChangeInfo="false";
		// tr_slipCreate.post();
        $c.sbm.execute(sbm_slipCreate);
	}
};

//-------------------------------------------------------------------------
// 전표삭제
//-------------------------------------------------------------------------
scwin.f_slipDel = async function() {
	//전표생성여부 검사
	let rtn = "";
	let inYm = "";
	let wrkPlCd = "";
	inYm 	= ica_inYmSlip.getValue();
	wrkPlCd = lc_WrkPlCdSlip.getValue();
    rtn = await udc_jobClose.cfJobCloseYN("CUR", inYm, "00", "EQ06", wrkPlCd, "", "N");

 	if ( rtn != "2" ) {
		await $c.win.alert( lc_WrkPlCdSlip.getText(true) + "에 대한 부품매입전표를 아직 생성하지 않았습니다.");
		return;
	}

    if( await $c.win.confirm($c.data.getMessage(MSG_CM_CRM_008,"전표"))==true ){	//"@을(를) 삭제하시겠습니까?"
		dma_slip_cond.set("inYm", ica_inYmSlip.getValue());
		dma_slip_cond.set("wrkPlCd", lc_WrkPlCdSlip.getValue());
		// tr_slipDelete.post();
        $c.sbm.execute(sbm_slipDelete);
	}
};

scwin.udc_acctDeptCd_onblurCodeEvent = function (e) {
    scwin.f_openCommonPopUp(1, ed_acctDeptCd.getValue(), ed_acctDeptNm.getValue(),'T','T');
};

scwin.udc_acctDeptCd_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(1, ed_acctDeptCd.getValue(), ed_acctDeptNm.getValue(),'F','T');
};

scwin.udc_acctDeptCd_callback = function(rtnList) {
    if (rtnList != null ) {
    	if (rtnList[0] != "N/A") {
    		ed_acctDeptCd.setValue(rtnList[0]);
			ed_acctDeptCd.options.hidVal = rtnList[0];
			ed_acctDeptNm.setValue(rtnList[1]);
		}
    } else {
		ed_acctDeptCd.setValue("");
		ed_acctDeptCd.options.hidVal = "";
		ed_acctDeptNm.setValue("");
    }
};

//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = async function(disGubun, pCode, pName, pClose, pAllSearch) {
	// 선언부
	switch (disGubun)
	{
	case 1:
		//귀속부서 팝업
		// rtnList = cfCommonPopUp('retrieveAcctDeptCdInfo'	// XML상의 SELECT ID	
        await udc_acctDeptCd.cfCommonPopUp(
                                 scwin.udc_acctDeptCd_callback 	// XML상의 SELECT ID	
								,pCode					// 화면에서의 ??? Code Element의	Value
								,pName					// 화면에서의 ??? Name Element의	Value
								,pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
								,null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
								,null					// Title순서	
								,null					// 보여주는 각 컬럼들의 폭	
								,null					// 컬럼중에서 숨기는	컬럼 지정	
								,null					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
								,null					// POP-UP뛰을때 원도우의	사용자 정의	폭
								,null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
								,null					// 윈도우 위치 Y좌표	
								,null					// 윈도우 위치 X좌표
								,null					// 중복체크여부	("F")
								,pAllSearch					// 전체검색허용여부	("F")
								,"귀속부서,귀속코드,부서명"		// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
								);
		break;
	}
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function(inObj, pairObj, disGubun, isCode) {
	// 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
	if (!cfCanOpenPopup(inObj, pairObj))
	    return;

	// 짝이 되는 오브젝트의 값 제거
	cfClearPairObj(pairObj);

	// 검색어 세팅
	let pVal = cfGetValue(inObj);

	// inObj가 코드 필드일 경우 팝업
	if (isCode == null || isCode == true)
	    f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
	// inObj가 코드명 필드일 경우 팝업
	else
	    f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
};

//-------------------------------------------------------------------------
// Popup
//-------------------------------------------------------------------------
scwin.f_ofcPopUp = function(em_name, popbool) {
    let tmpofcnm = eval(em_name + "Nm").text;
    let tmpcd = "";
    if ( popbool == "T" ) {
        tmpcd  = eval(em_name + "Cd").text;
    }
    let firstList = cfCommonPopUp('retrieveAcctDeptCdInfo', tmpcd, "",popbool, 2,null,null,null,null,null); // 귀속부서조회
    if ( firstList != null) {
        if ( firstList[0] == "N/A" ) { 
            eval(em_name + "Cd").Text = "";
            eval(em_name + "Nm").Text = "";
    }
        eval(em_name + "Cd").Text = firstList[0];    // 귀속부서코드
        eval(em_name + "Nm").Text = firstList[1];    // 귀속부서명
    } else {
        eval(em_name + "Cd").Text = "";
        eval(em_name + "Nm").Text = "";
    }
};

