//------------------------------------------------------------------------
// 리포트 출력 버튼
//------------------------------------------------------------------------
scwin.f_OzReport = async function() {
	// //필수입력항목 체크	  
  	// if( !cfValidate([ed_inYm]) ) return;
    let ret = await $c.gus.cfValidate([ica_inYm]);
    if (!ret) {
        return false;
    }

    let data = {
        reportName: "/ps/eq/adjmmgnt/matprscond/eq_520_01_03.ozr",
        odiParam : {
                     inYm: ica_inYm.getValue()
                    ,wrkPlCd: lc_WrkPlCd.getValue()==null?"":lc_WrkPlCd.getValue()
        },
        viewerParam : {
            useprogressbar : false, // 프로그레스바 쓸지 말지
            printcommand : true,
            zoom : 90, // 배율 설정
        },
        formParam: {

        }
    };
    scwin.openPopup(data);
};

scwin.openPopup = async function(data){
    let opts = {
        id: "ozReportPopup",
        popupName: "오즈 리포트",
        modal: true,
        type: "browserPopup",
        width: 1000,
        height: 600,
        title: "오즈 리포트"
    };
    await $c.win.openPopup("/ui/cm/zz/ozreportPopup.xml", opts, data);
};

//-------------------------------------------------------------------------
// 엑셀 출력
//-------------------------------------------------------------------------
scwin.f_Excel = async function() {
	//필수입력항목 체크	  
  	let ret = await $c.gus.cfValidate([ica_inYm]);
    if (!ret) {
        return false;
    } 
	let rowCnt = ds_eq420.getRowCount();
	if ( rowCnt > 0 ) {

        let sheetTitle = "월 업체별 정비자재 입고현황";
        const options = {
            fileName: sheetTitle + ".xlsx",
            sheetName: sheetTitle
        };
        $c.data.downloadGridViewExcel(gr_eq420, options);

	} else {
		// cfAlertMsg(MSG_CM_WRN_018,['[월 업체별 정비자재 입고현황] 자료','[조회]']);
        $c.win.alert($c.data.getMessage(MSG_CM_WRN_018, "[월 업체별 정비자재 입고현황] 자료","[조회]"));
	}
};

