//-------------------------------------------------------------------------
// 대표정비작업장콤보 조회
//-------------------------------------------------------------------------
scwin.f_RetrieveSecond = function(param1) { 
	dma_combo.set("cmd", "retriveFixWrkList");
	dma_combo.set("strVal", param1);
	dma_combo.set("intVal", "");
	$c.sbm.execute(sbm_searchCombo);
};

//-------------------------------------------------------------------------
// 대표정비작업장콤보 조회
