scwin.f_RetrieveSecondSlip = function(param1) { 
	dma_combo.set("cmd", "retriveFixWrkList");
	dma_combo.set("strVal", param1);
	dma_combo.set("intVal", "");
	$c.sbm.execute(sbm_searchComboSlip);
};

//-------------------------------------------------------------------------
// 컴포넌트 이벤트
//-------------------------------------------------------------------------
scwin.btn_search1_init_onclick = function (e) {
    $c.gus.cfInitObjects(table1);
    ica_inYm.setValue(scwin.currDate);
};

scwin.lc_homeClsCd_onchange = function (info) {
    let value = info.newValue;
	// 대표정비작업장콤보 조회
    scwin.f_RetrieveSecond(value);
};

scwin.lc_WrkPlCd_onchange = function (info) {
    let value = info.newValue;
    lc_WrkPlCdSlip.setValue(value);
};

scwin.lc_homeClsCdSlip_onchange = function (info) {
    let value = info.newValue;
	// 대표정비작업장콤보 조회
    scwin.f_RetrieveSecondSlip(value);
};

scwin.sbm_search_submitdone = function (e) {
    let rowCnt = ds_eq420.getRowCount();
    spanTotal.setLabel(rowCnt);
    if (rowCnt == 0) {
        $c.win.alert(MSG_CM_WRN_002); // 조회결과가 존재하지 않습니다
    } else {
        gr_eq420.setFocusedCell(0, 0);
    }
};

scwin.gr_eq420_oncellclick = function (rowIndex, columnIndex, columnId) {
    let Colid = columnId;
    if ( Colid=="slipNo" && ds_eq420.getCellData(rowIndex, "slipNo")!="" ){
    	$c.gus.cfShowSlipInfo(ds_eq420.getCellData(rowIndex, Colid));
    }
    if ( Colid=="vatAmt" && ds_eq420.getCellData(rowIndex, "slipNo") == "" ){
    	gr_eq420.setCellReadOnly(rowIndex, "vatAmt", false);
    } else {
        gr_eq420.setCellReadOnly(rowIndex, "vatAmt", true);
    }
};

scwin.sbm_slipCreate_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;
    await $c.win.alert("전표 생성 완료");
	scwin.f_Retrieve();    
};


scwin.sbm_slipDelete_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;
    await $c.win.alert("전표 삭제 완료");
	scwin.f_Retrieve();
};

scwin.ica_inYm_onblur = function (e) {
    console.log(ica_inYm.getValue());
    if (ica_inYm.getValue().length == 6){
        ica_inYmSlip.setValue(ica_inYm.getValue());
    }

};

scwin.gr_eq420_onviewchange = function (info) {
    let col = info.colId;
    let row = info.rowIndex;
    if ( col == "vatAmt"){
        let data = parseInt(ds_eq420.getCellData(row, "inAmt")) + parseInt(ds_eq420.getCellData(row, "vatAmt"));
        ds_eq420.setCellData(row, "totAmt", data);
    }
};

scwin.sbm_searchCombo_submitdone = function (e) {
    lc_homeClsCdSlip.setValue(lc_homeClsCd.getValue());
};

scwin.sbm_searchComboSlip_submitdone = function (e) {
